isDisabled:
{{
  (() => {
    // 1. Bloqueo por Alumno
    if (!sel_alumno.selectedOptionValue) return true;

    // 2. Validar que TODOS los widgets en la vista actual sean válidos
    // Esto revisa automáticamente si los "Required" están llenos y si los números son números
    const hayCamposInvalidos = List1.currentItemsView.some((fila) => {
      // Si alguno de estos es falso, some() devolverá true
      return !fila.inp_peso.isValid || 
             !fila.inp_reps.isValid || 
             !fila.sel_tecnica.isValid;
    });

    // 3. Si hay menos filas de las que dice tu utils, también bloqueamos
    const listaIncompleta = List1.currentItemsView.length < utils.ejerciciosDefault.length;

    return hayCamposInvalidos || listaIncompleta;
  })()
}}
